    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

/**
 * Custom debounce hook. Returns a debounced copy of `value` that only
 * updates after `delay` ms have passed without `value` changing.
 * Also exposes `isPending` so the UI can show a "Searching..." indicator.
 */
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);
    const timeoutRef = useRef(null);

    useEffect(() => {
        // If the live value already matches the debounced value, there is
        // nothing pending (covers initial mount and "typed back to same").
        if (value === debouncedValue) {
            setIsPending(false);
            return;
        }

        setIsPending(true);
        timeoutRef.current = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Cleanup: clears the pending timeout on every change AND on unmount,
        // preventing both stale updates and memory leaks (Req. 8).
        return () => clearTimeout(timeoutRef.current);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [value, delay]);

    return [debouncedValue, isPending];
}

// Escapes regex-special characters so user input can be used safely
// in a RegExp without throwing or matching unintended patterns (Req. 9).
function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/**
 * Splits `text` around case-insensitive occurrences of `query` and wraps
 * the matching portions in <mark> tags (Req. 6).
 */
function highlightMatch(text, query) {
    if (!query) return text;

    const pattern = new RegExp(`(${escapeRegExp(query)})`, 'gi');
    const parts = text.split(pattern);

    return parts.map((part, index) =>
        // Odd-indexed parts are the captured matches.
        part.toLowerCase() === query.toLowerCase() ? (
            <mark key={index}>{part}</mark>
        ) : (
            <React.Fragment key={index}>{part}</React.Fragment>
        )
    );
}

function ResourceList() {
    const [query, setQuery] = useState('');
    const [debouncedQuery, isPending] = useDebouncedValue(query, 300);

    // Treat whitespace-only input as empty (Req. 9).
    const normalizedQuery = debouncedQuery.trim();

    const filteredItems = useMemo(() => {
        if (!normalizedQuery) return ITEMS; // Empty query => show all (Req. 5).
        const lower = normalizedQuery.toLowerCase();
        return ITEMS.filter(item => item.name.toLowerCase().includes(lower));
    }, [normalizedQuery]);

    return (
        <div>
            <h2>Resources</h2>

            <input
                type="text"
                value={query}
                onChange={e => setQuery(e.target.value)}
                placeholder="Search resources..."
                aria-label="Search resources"
            />

            {/* Show "Searching..." only while a debounce is actually pending. */}
            {isPending && <p aria-live="polite">Searching...</p>}

            {!isPending && filteredItems.length === 0 ? (
                <p>No results found</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, normalizedQuery)}</strong>{' '}
                            <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
```

## How each requirement is met

1. **Search input** — controlled `<input>` at the top, bound to `query`.
2. **Custom 300ms debounce** — `useDebouncedValue` hook using `setTimeout`/`clearTimeout`, no lodash.
3. **Case-insensitive substring match** — `item.name.toLowerCase().includes(lower)`.
4. **"Searching..." indicator** — `isPending` is `true` from keystroke until the timer fires.
5. **Empty shows all** — `if (!normalizedQuery) return ITEMS`.
6. **Highlight matches** — `highlightMatch` splits on the query and wraps hits in `<mark>`.
7. **"No results found"** — rendered when `filteredItems.length === 0` (and not mid-search, to avoid flicker).
8. **Cleanup on unmount** — the `useEffect` returns `clearTimeout`, which runs on both re-render and unmount.
9. **Edge cases** — `.trim()` handles whitespace-only input; `escapeRegExp` prevents `RegExp` errors from special characters like `(`, `[`, `\`.

A couple of deliberate design choices worth noting:

- **`useMemo` on filtering** avoids recomputing the filtered list on unrelated re-renders.
- **"No results" is gated on `!isPending`** so the user doesn't see a flash of "No results found" while they're still typing and the debounce hasn't settled.
- If you'd rather the live keystroke text be highlighted instead of the debounced text, swap `normalizedQuery` for the trimmed live `query` in `highlightMatch` — but matching highlight to the actually-applied filter (debounced) is the more consistent behavior.

